@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix ns1: <https://cdif.org/0.1/> .
@prefix ns2: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix ns3: <http://spdx.org/rdf/terms#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a ns2:PhysicalDataSet,
                        ns2:StructuredDataSet,
                        schema1:DataDownload ;
                    schema1:contentUrl "https://example.org/data/gom-temp-cube-2025.nc" ;
                    schema1:encodingFormat "application/x-netcdf" ;
                    schema1:name "Gulf of Maine temperature cube (NetCDF-4)" ;
                    ns3:checksum [ a ns3:Checksum ;
                            ns3:algorithm "SHA256" ;
                            ns3:checksumValue "9f3c1a0b4e8d2f1e7a6c5b4d3a2918f0e1d2c3b4a5968778a9b0c1d2e3f40516" ] ;
                    ns1:fileSize 1.846e+02 ;
                    ns1:fileSizeUofM "MB" ;
                    ns1:hasPhysicalMapping [ ns2:isRequired true ;
                            ns2:locator "/temperature" ;
                            ns2:nullSequence "NaN" ;
                            ns1:format "decimal" ;
                            ns1:formats_InstanceVariable <https://example.org/var-temperature> ;
                            ns1:physicalDataType "float32" ],
                        [ ns2:isRequired true ;
                            ns2:locator "/time" ;
                            ns1:format "days since 2024-01-01" ;
                            ns1:formats_InstanceVariable <https://example.org/var-time> ;
                            ns1:physicalDataType "int32" ],
                        [ ns2:isRequired true ;
                            ns2:locator "/lat" ;
                            ns1:format "decimal" ;
                            ns1:formats_InstanceVariable <https://example.org/var-lat> ;
                            ns1:physicalDataType "float32" ],
                        [ ns2:isRequired true ;
                            ns2:locator "/depth" ;
                            ns1:format "decimal" ;
                            ns1:formats_InstanceVariable <https://example.org/var-depth> ;
                            ns1:physicalDataType "float32" ],
                        [ ns2:isRequired true ;
                            ns2:locator "/lon" ;
                            ns1:format "decimal" ;
                            ns1:formats_InstanceVariable <https://example.org/var-lon> ;
                            ns1:physicalDataType "float32" ] ] ;
            sh:resultMessage "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Info ] ] .

